pipeline {
    agent any
    
    parameters {
        string(name: 'IMAGE_TAG', defaultValue: 'latest', description: 'Image tag for Docker image')
        string(name: 'REGISTRY_URL', defaultValue: '', description: 'Docker registry URL')
